<?php
/**
 * AdyMob Elementor Plugin Installer
 * ۱. این فایل را در root وردپرس آپلود کنید
 * ۲. در مرورگر باز کنید: https://yourdomain.com/adymob-installer.php
 * ۳. بعد از نصب این فایل را پاک کنید
 */
if (!defined("ABSPATH")) {
    $r = __DIR__;
    while (!file_exists($r."/wp-load.php") && strlen($r) > 3) $r = dirname($r);
    if (!file_exists($r."/wp-load.php")) die("wp-load.php پیدا نشد.");
    require $r."/wp-load.php";
}
if (!current_user_can("install_plugins")) {
    auth_redirect();
    exit;
}
$raw   = base64_decode('');
$data  = json_decode(gzdecode($raw), true);
$base  = WP_CONTENT_DIR."/plugins/adymob-elementor/";
$ok = $err = [];
foreach ($data as $rel => $content) {
    $path = $base . $rel;
    if (!is_dir(dirname($path))) wp_mkdir_p(dirname($path));
    file_put_contents($path, $content) !== false ? $ok[] = $rel : $err[] = $rel;
}
echo "<!DOCTYPE html><html dir=rtl><head><meta charset=UTF-8><style>body{font-family:Tahoma;margin:40px;direction:rtl}h2{color:#D97706}</style></head><body>";
echo "<h2>AdyMob — نصب‌کننده</h2>";
if (empty($err)) {
    echo "<p>✅ <b>".count($ok)." فایل با موفقیت ایجاد شد.</b></p>";
    echo '<p><a href="'.admin_url('plugins.php').'">← برو به افزونه‌ها و AdyMob را فعال کن</a></p>';
} else {
    echo "<p>".count($ok)." فایل ایجاد شد.</p><p style=color:red>خطا: ".implode(", ",$err)."</p>";
}
echo "<p style=color:red><b>⚠️ این فایل را از سرور پاک کنید!</b></p></body></html>";
